python3 -c "
import sqlite3
old = sqlite3.connect('/Users/allenbot/project/auto-trading/lab/reports/seed_v3_pre_cache.db')
new = sqlite3.connect('/Users/allenbot/project/auto-trading/lab/reports/seed_v3.db')

old_data = {r[0]: (r[1], r[2]) for r in old.execute('SELECT strategy, total_trades, total_return FROM combo_summary WHERE coin=\"BTC\" AND interval=\"1h\"')}
new_data = {r[0]: (r[1], r[2]) for r in new.execute('SELECT strategy, total_trades, total_return FROM combo_summary WHERE coin=\"BTC\" AND interval=\"1h\"')}

changed = []
same = 0
for s in sorted(old_data):
    if s in new_data:
        ot, nt = old_data[s][0], new_data[s][0]
        if ot != nt:
            changed.append((s, ot, nt, nt - ot))
        else:
            same += 1

print(f'BTC/1h 对比: {same}个相同, {len(changed)}个变化')
print()
if changed:
    print(f'{\"策略\":<30} {\"旧\":>8} {\"新\":>8} {\"差\":>8}')
    print('-' * 60)
    for s, ot, nt, d in sorted(changed, key=lambda x: abs(x[3]), reverse=True):
        print(f'{s:<30} {ot:>8} {nt:>8} {d:>+8}')

old.close()
new.close()
"
